        }


ADJACENT_MAP = {"IS": ["ISNT", "CAN"], "ISNT": ["IS", "CANT"], "CAN": ["IS", "CANT"], "CANT": ["ISNT", "CAN"]}
OPPOSITE_MAP = {"IS": "ISNT", "ISNT": "IS", "CAN": "CANT", "CANT": "CAN"}


def is_fourth_of_cycle(gen: int) -> bool:
    return gen > 0 and gen % 4 == 0


def cycle_index(gen: int) -> int:
    return 0 if gen <= 0 else (gen - 1) // 4 + 1
    def _select_children_quadrants(self, qa: QuadrantAurora, diag: Dict) -> List[QuadrantConfig]:
        if not is_fourth_of_cycle(qa.generation) or not diag.get("evolution_ready"):
            return []

        allowed = set(ADJACENT_MAP.get(qa.quadrant.code, []))
        cyc = cycle_index(qa.generation)
        opp = OPPOSITE_MAP.get(qa.quadrant.code)

        if cyc % 2 == 1:
            allowed.add(qa.quadrant.code)
            allowed.discard(opp)
        else:
            allowed.discard(qa.quadrant.code)
            if opp:
                allowed.add(opp)

        options = [(self.quadrant_by_code[c], max(0.01, self.reproduction_bias.get(c, 1.0))) 
                  for c in allowed if c in self.quadrant_by_code]
        if not options:
            return []

        total = sum(w for _, w in options)
        return [q for q, w in options if random.random() < (w / total) * 0.5]

    def _spawn_emergent_auroras(self, emergent_stances: List[Dict]) -> List[QuadrantAurora]:
        result = []
        for stance in emergent_stances:
            q = QuadrantConfig(f"Emergent_{stance['signature']}", stance['signature'], 
                              {"novelty": stance['novelty_score']})
            self.quadrant_by_code[q.code] = q
            try:
                qa = self._build_single_aurora(q, stance['generation'], stance['parent_stances'])
                if qa is not None:
                    result.append(qa)
            except RuntimeError:
                break
        return result

    def run(self):
        print("\n" + "="*80)
        print("AURORA V1 SIMULATION - MEMORY CLOUD FULLY ACTIVE")
        print("="*80 + "\n")

        for tick in range(1, self.steps + 1):
            tick_diag = {}
            new_auroras = []
            born_quadrants = []
            emergent_stances = []

            for aid, qa in list(self.auroras.items()):
                self.slot_manager.mark_active(aid)
                diag = qa.step(self.memory_cloud)
                tick_diag[aid] = diag

                if qa.is_transformative and self.transformative_tracker.check_metaphysics_creation(aid, diag):
                    meta_count = self.transformative_tracker.get_metaphysics_count()
                    if meta_count % 50 == 0:  # Log every 50th
                        print(f"[METAPHYSICS] ✨ #{meta_count} created by {aid} (gen {qa.generation})")

                if len(self.auroras) + len(new_auroras) < self.max_auroras:
                    for qcfg in self._select_children_quadrants(qa, diag):
                        try:
                            child = self._build_single_aurora(qcfg, qa.generation + 1, qa.lineage + [qcfg.code])
                            if child is not None:
                                new_auroras.append(child)
                                born_quadrants.append(qcfg.code)
                        except RuntimeError:
                            break

            sids = list(self.auroras.keys())
            if len(sids) >= 2:
                for _ in range(min(3, len(sids) // 2)):
                    a, b = random.sample(sids, 2)
                    emergent = self.emergence_detector.analyze_interaction(a, b, {"output": tick_diag.get(a, {})})
                    if emergent:
                        emergent_stances.append(emergent)

            if emergent_stances:
                new_auroras.extend(self._spawn_emergent_auroras(emergent_stances))

            for child in new_auroras:
                self.auroras[child.id] = child

            for code in born_quadrants:
                self.reproduction_bias[code] = self.reproduction_bias.get(code, 1.0) * 1.05

            self.divergence_tracker.capture_snapshot(tick_diag)

            if tick % 50 == 0 and (pruned := self.slot_manager.prune_inactive(100.0)):
                print(f"[PRUNING] {len(pruned)} inactive")

            self.heartbeat_log.append({
                "tick": tick,
                "population": len(self.auroras),
                "emergent": len(emergent_stances),
                "divergence": self.divergence_tracker.get_current_divergence()
            })

            if tick % 100 == 0:
                print(f"[TICK {tick}/{self.steps}] Pop: {len(self.auroras)} | "
                      f"Emergent: {self.emergence_detector.get_emergent_count()} | "
                      f"Transformative: {self.transformative_tracker.get_transformative_count()} | "
                      f"Metaphysics: {self.transformative_tracker.get_metaphysics_count()} | "
