def load_module_prefer_normal(name, prefix=None):
    try:
        return importlib.import_module(name)
    except:
        pass
    p = prefix or name
    for fn in os.listdir(THIS_DIR):
        if fn.endswith(".py") and fn.startswith(p):
            try:
                return SourceFileLoader(p, os.path.join(THIS_DIR, fn)).load_module()
            except:
