LOG_DIR = "free_roam_logs"

class FreeRoamSimulationEngine(SimulationEngine):

    def __init__(self):
        super().__init__(
            max_steps=200000,
            candidates_per_step=16,
            fine_grain_until_step=50000,
            snapshot_interval=2000,
            summary_interval=20000,
            log_dir=LOG_DIR
        )
