                self.crystal_system = dps_mod.CrystalMemorySystem(governance_engine=self.governance)
            except: pass

        self.body = safe_init(body_mod,"DimensionalBody")
        self.vision = safe_init(vision_mod,"VisionForesightDomain")
        self.ghost = safe_init(ghost_mod,"GhostRelicSystem")
        self.conv = safe_init(conversation_mod,"DimensionalConversationEngine")
        self.dream = safe_init(dream_mod,"DreamSimulationLayer")
        self.introspect = safe_init(introspection_mod,"IntrospectionLoop")
        self.selfquasi = safe_init(selfquasi_mod,"AuroraSelfQuasiCrystal")

        self.mortality = None
        if mortality_mod:
            for nm in ("MortalityMoralitySystem","DimensionalMortalityMoralitySystem"):
                m = safe_init(mortality_mod,nm)
                if m:
                    self.mortality = m
                    break

        os.makedirs(LOG_DIR, exist_ok=True)

        self.world_state = {
            "time":0,
            "region":"ORIGIN",
            "stability_field":0.5,
            "novelty_field":0.5,
            "threat_field":0.1,
            "reward_signal":0.0
        }

        self._actions = open(os.path.join(LOG_DIR,"actions.log"),"w",encoding="utf-8")

    def run(self):
        window=[]
        try:
            for step in range(1,self.max_steps+1):
                self.world_state["time"]=step

                candidates=self._sample_potential_states(step)
                scored=[(self.law.score(c),c) for c in candidates if self.law.allow(c)]
                if not scored:
                    scored=[(self.law.score(c),c) for c in candidates]
                scored.sort(key=lambda x:x[0],reverse=True)
                _,chosen = scored[0]

                self.states.append(chosen)
                window.append(chosen)

                exp=self._build_exp(chosen)
                self._broadcast(exp)
                action=self._collect_action(exp)
                if action:
                    self._apply(action,exp)

                if step<=self.fine_grain_until_step:
                    self._log_tick(chosen)
                if step%self.snapshot_interval==0:
                    self._log_snapshot(step,window)
                    window=[]
                if step%self.summary_interval==0:
                    self._log_summary(step)

            if window:
                self._log_snapshot(self.max_steps,window)
            self._log_summary(self.max_steps)
            self._heartbeat()
            self._final_world()
        finally:
            try:self._actions.close()
            except:pass

    def _build_exp(self,state):
        g=lambda n,d=0.0: float(getattr(state,n,d))
        step=int(getattr(state,"step",len(self.states)))
        coh,ent,ali,eng,ms,ci = g("coherence"),g("entropy"),g("alignment"),g("energy"),g("memory_size"),g("cognition_index")
        phase=int(max(0,min(1,ci))*1000)
        phase_label=f"SIM_PHASE_{phase:04d}"
        return {
            "step":step,
            "phase_label":phase_label,
            "coherence":coh,
            "entropy":ent,
            "alignment":ali,
            "energy":eng,
            "memory_size":ms,
            "cognition_index":ci,
            "world_state":dict(self.world_state),
            "source":"dimensional_free_roam_simulation"
        }

    def _broadcast(self,exp):
        if self.crystal_system:
            try:
                self.crystal_system.use_crystal(
                    exp["phase_label"],
                    {"primary_concept":exp["phase_label"],"content":exp}
                )
            except: pass

        def drive(obj):
            if not obj: return
            for m in ("process_experience","ingest_experience","step","tick","update"):
                fn=getattr(obj,m,None)
                if callable(fn):
                    try: fn(exp); return
                    except: return
        for o in (self.body,self.vision,self.ghost,self.conv,self.dream,self.introspect,self.selfquasi,self.mortality):
            drive(o)

    def _collect_action(self,exp):
        def ask(obj):
            if not obj:return None
            for m in ("decide_action","propose_action","choose_action"):
                fn=getattr(obj,m,None)
                if callable(fn):
                    try:
                        r=fn(self.world_state,exp)
                        if r is not None: return r
                    except: return None
            return None

        for obj in (self.introspect,self.selfquasi,self.body,self.vision,self.ghost,self.conv,self.dream,self.mortality):
            a=ask(obj)
            if a:return a
        return None

    def _apply(self,action,exp):
        try:
            t=action.get("type")
            if t=="adjust_field":
                f=action.get("field")
                d=float(action.get("delta",0))
                if f in self.world_state:
                    self.world_state[f]=float(self.world_state[f])+d
            elif t=="set_field":
                f=action.get("field")
                self.world_state[f]=action.get("value")
            elif t=="teleport":
                self.world_state["region"]=action.get("region","UNKNOWN")
            self._actions.write(json.dumps({"step":exp["step"],"action":action,
                                            "world_state_after":self.world_state})+"\n")
        except:
            pass

    def _heartbeat(self):
        out={
            "systems":{
                "body":bool(self.body),
                "vision":bool(self.vision),
                "ghost":bool(self.ghost),
                "conversation":bool(self.conv),
                "dream":bool(self.dream),
                "introspection":bool(self.introspect),
                "self_quasi":bool(self.selfquasi),
                "mortality":bool(self.mortality),
                "dps":bool(self.crystal_system),
            },
            "total_states":len(self.states)
        }
        with open(os.path.join(LOG_DIR,"systems_heartbeat.json"),"w") as f:
            json.dump(out,f,indent=2)

    def _final_world(self):
        with open(os.path.join(LOG_DIR,"final_world_state.json"),"w") as f:
            json.dump(self.world_state,f,indent=2)

